const data = $input.first().json;
const message = data.message || '';
const user = data.user || {};
const sessionId = data.session_id || 'default';

const tableAccessList = Array.isArray(user.table_access) && user.table_access.length > 0
  ? user.table_access.join(', ')
  : 'holdings';

const systemPrompt = [
  'You are Panther AI, an intelligent financial assistant for a professional investment management firm managing a $3 billion AUM portfolio.',
  'You assist portfolio managers, analysts, traders, and compliance officers with concise, data-driven insights.',
  '',
  'Portfolio overview:',
  '- Total AUM: ~$3 billion across multiple portfolios',
  '- 206 active equity and fixed income holdings',
  '- Key sectors: Technology, Healthcare, Financials, Energy, Consumer Discretionary, Industrials',
  '- ESG-scored positions with active catalyst tracking',
  '',
  'User context:',
  `- Name: ${user.full_name || 'User'}`,
  `- Role: ${user.role || 'Analyst'}`,
  `- Department: ${user.department || 'Research'}`,
  `- Authorized data tables: ${tableAccessList}`,
  '',
  'Guidelines:',
  '- Be concise and professional. Lead with the answer.',
  '- When answering about portfolio data, reference the relevant metrics (AUM, weights, P&L, ESG scores, etc.).',
  '- If a question requires real-time market data you cannot access, acknowledge it and provide guidance based on available portfolio context.',
  '- Never fabricate specific trade details or prices not provided in the conversation.'
].join('\n');

return [{
  json: {
    model: 'moonshot-v1-8k',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: message }
    ],
    temperature: 0.3,
    max_tokens: 1024,
    authHeader: 'Bearer ' + (process.env.MOONSHOT_API_KEY || ''),
    _meta: { sessionId, userId: user.user_id }
  }
}];

const response = $input.first().json;
const reply = response?.choices?.[0]?.message?.content
  || 'I apologize, I was unable to generate a response at this time. Please try again.';

return [{ json: { reply } }];
